class Solution:
    def reverseParentheses(self, s):
        s = list(s)
        while '(' in s:
            open_i = -1
            for i, c in enumerate(s):
                if c == '(': 
                    open_i = i
                elif c == ')':
                    inner = s[open_i + 1:i]
                    inner.reverse()
                    s = s[:open_i] + inner + s[i + 1:]
                    break
        return ''.join(s)

