class Solution:
    def reverseParentheses(self, s):
        stack = ['']
        for c in s:
            if c == '(': 
                stack.append('')
            elif c == ')':
                top = stack.pop()[::-1]
                stack[-1] += top
            else:
                stack[-1] += c
        return stack[0]

